// ML-DSA-44 (tz5) interop vectors generated by the official Octez client
// "octez-client 25.0~rc1" (protocol U025 / PsUshuai9Qap):
//   octez-client gen keys tz5test --sig mldsa44
//   octez-client show address tz5test -S
//   octez-client -p PsUshuai9Qap sign bytes 0x0123456789 for tz5test
// This is a throwaway test key (no funds). ML-DSA verification is deterministic,
// so octezSignature reliably verifies; signing is randomized but always verifies.
export const mldsaSecretKey = "";
export const mldsaPublicKey = "";
export const mldsaPublicKeyHash = "tz5aAUqMhjLFyXdN2VaFSSvhWMQ8dnXq9LzA";
/** the bytes passed to octez `sign bytes 0x...` (hex, no 0x, no watermark) */
export const octezSignedBytesHex = "0123456789";
/** signature produced by octez-client for octezSignedBytesHex with this key */
export const octezSignature = "";
